void print_logo(uMint size, char language)
{
	switch (language)
	{
		case 'e':
			print_logo(size, 0, 's');
			break;
		case 'z':
			print_logo(size, 1, 's');
			break;
		case 'f':
			print_logo(size, 2, 's');
			break;
	
		default:
			print_logo(size, 0, 's');
			break;
	}
}

void print_logo(uMint size, int language)
{
	print_logo(size, language, 's');
}

void print_logo(uMint size, char language, char spam_log)
{
	switch (language)
	{
		case 'e':
			print_logo(size, 0, spam_log);
			break;
		case 'z':
			print_logo(size, 1, spam_log);
			break;
		case 'f':
			print_logo(size, 2, spam_log);
			break;
	
		default:
			print_logo(size, 0, spam_log);
			break;
	}
}
